fn collect_values_from_subschema(
    subschema: &serde_json::Value,
    suggestions: &mut Vec<ValueSuggestion>,
) {
    if let Some(const_val) = subschema.get("const") {
        if !suggestions.iter().any(|s| matches!(s, ValueSuggestion::Const(v) if v == const_val)) {
            suggestions.push(ValueSuggestion::Const(const_val.clone()));
        }
        return;
    }

    if let Some(enum_vals) = subschema.get("enum").and_then(|v| v.as_array()) {
        for val in enum_vals {
            let already_exists = suggestions.iter().any(|s| match s {
                ValueSuggestion::Enum(e) => e == val,
                _ => false,
            });
            if !already_exists {
                suggestions.push(ValueSuggestion::Enum(val.clone()));
            }
        }
        return;
    }

    // Check type field вЂ” handle both string and array.
    if let Some(type_val) = subschema.get("type") {
        let types = match type_val {
            serde_json::Value::String(s) => vec![s.as_str()],
            serde_json::Value::Array(arr) => arr.iter().filter_map(|v| v.as_str()).collect::<Vec<_>>(),
            _ => vec![],
        };
        for t in types {
            match t {
                "boolean" if !suggestions.iter().any(|s| matches!(s, ValueSuggestion::Boolean)) => {
                    suggestions.push(ValueSuggestion::Boolean)
                }
                "null" if !suggestions.iter().any(|s| matches!(s, ValueSuggestion::Null)) => {
                    suggestions.push(ValueSuggestion::Null)
                }
                _ => {}
            }
        }
    }
}

/// Collect possible value suggestions for a property at the given pointer path.
///
/// Navigates to the subschema at `pointer` + `property_name`, then inspects
/// `enum`, `const`, `type`, `nullable`, `anyOf`, and `oneOf` to generate
/// value suggestions. Duplicate suggestions are deduplicated.
pub fn collect_values(
    root: &serde_json::Value,
    pointer: &[String],
    property_name: &str,
) -> Vec<ValueSuggestion> {
    let mut full_pointer: Vec<String> = pointer.to_vec();
    full_pointer.push(property_name.to_string());

    let Some(subschema) = resolve_subschema_at_pointer(root, &full_pointer) else {
        return vec![];
    };

    let mut suggestions = Vec::new();

    // Collect from the resolved subschema directly.
    collect_values_from_subschema(subschema, &mut suggestions);

    // Check for `nullable: true` (deprecated Draft 7 / schema.org annotation).
    if subschema.get("nullable").and_then(|v| v.as_bool()) == Some(true) {
        if !suggestions.iter().any(|s| matches!(s, ValueSuggestion::Null)) {
            suggestions.push(ValueSuggestion::Null);
        }
    }

    // Collect from anyOf branches.
    if let Some(any_of) = subschema.get("anyOf").and_then(|v| v.as_array()) {
        for branch in any_of {
            collect_values_from_subschema(branch, &mut suggestions);
        }
    }

    // Collect from oneOf branches.
    if let Some(one_of) = subschema.get("oneOf").and_then(|v| v.as_array()) {
        for branch in one_of {
            collect_values_from_subschema(branch, &mut suggestions);
        }
    }

    suggestions
}

