    #[test]
    fn hover_truncate_multibyte_boundary() {
        // Place a 4-byte emoji (U+1F600) right at the 10,000-byte boundary.
        let prefix = "x".repeat(9_999);
        let long_desc = format!("{prefix}\u{1F600}extra");

        let schema = serde_json::json!({
            "properties": {
                "x": { "description": long_desc }
            }
        });

        // Must not panic, and must produce valid truncated output.
        let result = lookup_hover_content(&schema, &["x".into()]).unwrap();
        assert!(result.ends_with("..."));
        // The emoji straddles byte 10,000, so it should be excluded.
        assert!(!result.contains('\u{1F600}'));
    }

    #[test]
    fn collect_properties_anyof_merge() {
        let schema = serde_json::json!({
            "anyOf": [
                {
                    "properties": {
                        "name": { "type": "string" }
                    },
                    "required": ["name"]
                },
                {
                    "properties": {
                        "age": { "type": "number" }
                    }
                }
            ]
        });
        let props = collect_properties(&schema, &[]);
        assert_eq!(props.len(), 2);
        let name_prop = props.iter().find(|p| p.name == "name").unwrap();
        assert!(name_prop.required);
        let age_prop = props.iter().find(|p| p.name == "age").unwrap();
        assert!(!age_prop.required);
    }

    #[test]
    fn collect_properties_oneof_merge() {
        let schema = serde_json::json!({
            "oneOf": [
                {
                    "properties": {
                        "email": { "type": "string" }
                    },
                    "required": ["email"]
                },
                {
                    "properties": {
                        "phone": { "type": "string" }
                    },
                    "required": ["phone"]
                }
            ]
        });
        let props = collect_properties(&schema, &[]);
        assert_eq!(props.len(), 2);
        let email_prop = props.iter().find(|p| p.name == "email").unwrap();
        assert!(email_prop.required);
        let phone_prop = props.iter().find(|p| p.name == "phone").unwrap();
        assert!(phone_prop.required);
    }

    #[test]
    fn collect_properties_dedup_allof_anyof_same_property() {
        let schema = serde_json::json!({
            "allOf": [
                {
                    "properties": {
                        "name": { "type": "string", "description": "From allOf" }
                    }
                },
                {
                    "anyOf": [
                        {
                            "properties": {
                                "name": { "type": "string", "description": "From anyOf" }
                            }
                        }
                    ]
                }
            ]
        });
        let props = collect_properties(&schema, &[]);
        assert_eq!(props.len(), 1);
        assert_eq!(props[0].name, "name");
        // Should have the first one collected (allOf branch).
        assert_eq!(props[0].description, Some("From allOf".to_string()));
    }

    #[test]
    fn collect_values_enum_anyof() {
        let schema = serde_json::json!({
            "properties": {
                "status": {
                    "anyOf": [
                        { "enum": ["active", "inactive"] },
                        { "enum": ["pending"] }
                    ]
                }
            }
        });
        let values = collect_values(&schema, &[], "status");
        assert_eq!(values.len(), 3);
        let labels: Vec<String> = values
            .iter()
            .filter_map(|v| match v {
                ValueSuggestion::Enum(e) => e.as_str().map(|s| s.to_string()),
                _ => None,
            })
            .collect();
        assert!(labels.contains(&"active".to_string()));
        assert!(labels.contains(&"inactive".to_string()));
        assert!(labels.contains(&"pending".to_string()));
    }

    #[test]
    fn collect_values_enum_oneof() {
        let schema = serde_json::json!({
            "properties": {
                "format": {
                    "oneOf": [
                        { "const": "json" },
                        { "const": "yaml" },
                        { "const": "toml" }
                    ]
                }
            }
        });
        let values = collect_values(&schema, &[], "format");
        assert_eq!(values.len(), 3);
        let labels: Vec<String> = values
            .iter()
            .filter_map(|v| match v {
                ValueSuggestion::Const(e) => Some(e.to_string()),
                _ => None,
            })
            .collect();
        assert!(labels.contains(&"\"json\"".to_string()));
        assert!(labels.contains(&"\"yaml\"".to_string()));
        assert!(labels.contains(&"\"toml\"".to_string()));
    }

    #[test]
    fn collect_values_nullable_type_array() {
        let schema = serde_json::json!({
            "properties": {
                "description": {
                    "type": ["string", "null"]
                }
            }
        });
        let values = collect_values(&schema, &[], "description");
        assert_eq!(values.len(), 2);
        assert!(matches!(&values[0], ValueSuggestion::Boolean | ValueSuggestion::Enum(_) | ValueSuggestion::Const(_)));
        assert!(values.iter().any(|v| matches!(v, ValueSuggestion::Null)));
    }

    #[test]
    fn collect_values_nullable_keyword() {
        let schema = serde_json::json!({
            "properties": {
                "nickname": {
                    "type": "string",
                    "nullable": true
                }
            }
        });
        let values = collect_values(&schema, &[], "nickname");
        assert_eq!(values.len(), 1);
        assert!(matches!(&values[0], ValueSuggestion::Null));
    }

    #[test]
    fn collect_values_deduplication() {
        let schema = serde_json::json!({
            "properties": {
                "mode": {
                    "oneOf": [
                        { "enum": ["dark", "light"] },
                        { "const": "dark" }
                    ]
                }
            }
        });
        let values = collect_values(&schema, &[], "mode");
        assert_eq!(values.len(), 2);
    }

    #[test]
    fn collect_values_boolean_and_null_combined() {
        let schema = serde_json::json!({
            "properties": {
                "flag": {
                    "type": ["boolean", "null"]
                }
            }
        });
        let values = collect_values(&schema, &[], "flag");
        assert!(values.iter().any(|v| matches!(v, ValueSuggestion::Boolean)));
        assert!(values.iter().any(|v| matches!(v, ValueSuggestion::Null)));
        assert_eq!(values.len(), 2);
    }

    #[test]
    fn collect_values_all_of_schemas() {
        let schema = serde_json::json!({
            "properties": {
                "value": {
                    "allOf": [
                        { "enum": ["a", "b"] },
                        { "enum": ["b", "c"] }
                    ]
                }
            }
        });
        let values = collect_values(&schema, &[], "value");
        assert_eq!(values.len(), 3);
        let labels: Vec<String> = values
            .iter()
            .filter_map(|v| match v {
                ValueSuggestion::Enum(e) => e.as_str().map(|s| s.to_string()),
                _ => None,
            })
            .collect();
        assert!(labels.contains(&"a".to_string()));
        assert!(labels.contains(&"b".to_string()));
        assert!(labels.contains(&"c".to_string()));
    }

    #[test]
    fn collect_values_nested_allof_with_ref() {
        let schema = serde_json::json!({
            "$defs": {
                "Role": {
                    "properties": {
                        "role": { "enum": ["admin", "user", "guest"] }
                    }
                }
            },
            "properties": {
                "user": {
                    "allOf": [
                        { "$ref": "#/$defs/Role" }
                    ]
                }
            }
        });
        let values = collect_values(&schema, &["user"].as_slice(), "role");
        assert_eq!(values.len(), 3);
        let labels: Vec<String> = values
            .iter()
            .filter_map(|v| match v {
                ValueSuggestion::Enum(e) => e.as_str().map(|s| s.to_string()),
                _ => None,
            })
            .collect();
        assert!(labels.contains(&"admin".to_string()));
        assert!(labels.contains(&"user".to_string()));
        assert!(labels.contains(&"guest".to_string()));
    }

    #[test]
    fn collect_properties_nested_allof() {
        let schema = serde_json::json!({
            "properties": {
                "server": {
                    "allOf": [
                        {
                            "properties": {
                                "host": { "type": "string" }
                            }
                        },
                        {
                            "anyOf": [
                                {
                                    "properties": {
                                        "port": { "type": "number" }
                                    }
                                }
                            ]
                        }
                    ]
                }
            }
        });
        let props = collect_properties(&schema, &["server".into()]);
        assert_eq!(props.len(), 2);
        let host_prop = props.iter().find(|p| p.name == "host").unwrap();
        assert_eq!(host_prop.schema_type.as_deref(), Some("string"));
        let port_prop = props.iter().find(|p| p.name == "port").unwrap();
        assert_eq!(port_prop.schema_type.as_deref(), Some("number"));
    }
}

