    subschema: &serde_json::Value,
    suggestions: &mut Vec<ValueSuggestion>,
) {
    if let Some(const_val) = subschema.get("const") {
        if !suggestions.iter().any(|s| matches!(s, ValueSuggestion::Const(v) if v == const_val)) {
            suggestions.push(ValueSuggestion::Const(const_val.clone()));
        }
        return;
    }

    if let Some(enum_vals) = subschema.get("enum").and_then(|v| v.as_array()) {
        for val in enum_vals {
            let already_exists = suggestions.iter().any(|s| match s {
                ValueSuggestion::Enum(e) => e == val,
                _ => false,
            });
            if !already_exists {
                suggestions.push(ValueSuggestion::Enum(val.clone()));
            }
        }
        return;
    }

    // Check type field вЂ” handle both string and array.
    if let Some(type_val) = subschema.get("type") {
        let types = match type_val {
            serde_json::Value::String(s) => vec![s.as_str()],
            serde_json::Value::Array(arr) => arr.iter().filter_map(|v| v.as_str()).collect::<Vec<_>>(),
            _ => vec![],
        };
        for t in types {
            match t {
                "boolean" if !suggestions.iter().any(|s| matches!(s, ValueSuggestion::Boolean)) => {
                    suggestions.push(ValueSuggestion::Boolean)
                }
                "null" if !suggestions.iter().any(|s| matches!(s, ValueSuggestion::Null)) => {
                    suggestions.push(ValueSuggestion::Null)
                }
                _ => {}
            }
        }
    }
}

